import type { Role } from "@/content/resume/experience";

export default function ExperienceList({ items }: { items: Role[] }) {
  return (
    <ul style={{ fontFamily: "var(--font-mono)", fontSize: "var(--t-sm-size)" }}>
      {items.map((r, i) => (
        <li key={i} style={{ padding: "var(--s-3) 0", borderLeft: "1px solid var(--rule)", paddingLeft: "var(--s-4)", marginBottom: "var(--s-3)" }}>
          <div style={{ display: "flex", justifyContent: "space-between", color: "var(--fg)" }}>
            <span>├── {r.title} <span style={{ color: "var(--fg-mute)" }}>· {r.org}</span></span>
            <span style={{ color: r.end === "Present" ? "var(--accent)" : "var(--fg-mute)" }}>
              {r.start} – {r.end}
            </span>
          </div>
          <div style={{ color: "var(--fg-dim)", marginTop: "var(--s-1)" }}>│   {r.scope}</div>
          {r.bullets.map((b, j) => (
            <div key={j} style={{ color: "var(--fg)", marginTop: "var(--s-1)" }}>│   · {b}</div>
          ))}
        </li>
      ))}
    </ul>
  );
}

import type { SkillGroup } from "@/content/resume/skills";

export default function SkillsTable({ groups }: { groups: SkillGroup[] }) {
  return (
    <table style={{ borderCollapse: "collapse", fontFamily: "var(--font-mono)", fontSize: "var(--t-sm-size)" }}>
      <thead>
        <tr>
          <th style={{ textAlign: "left", color: "var(--fg-mute)", paddingRight: "var(--s-5)", paddingBottom: "var(--s-2)", textTransform: "uppercase", fontWeight: "normal" }}>domain</th>
          <th style={{ textAlign: "left", color: "var(--fg-mute)", paddingBottom: "var(--s-2)", textTransform: "uppercase", fontWeight: "normal" }}>instruments</th>
        </tr>
      </thead>
      <tbody>
        {groups.map((g) => (
          <tr key={g.domain} style={{ verticalAlign: "top" }}>
            <td style={{ color: "var(--fg)", paddingRight: "var(--s-5)", paddingBottom: "var(--s-3)" }}>{g.domain}</td>
            <td style={{ color: "var(--fg-dim)", paddingBottom: "var(--s-3)" }}>{g.instruments.join(" · ")}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

